
import struct

hex_str = ""

def analyze(hex_s):
    # Hex string to bytes
    data = bytes.fromhex(hex_s)
    
    print(f"Total bytes: {len(data)}")
    
    # Try XOR FF on 8-byte chunks
    for i in range(0, len(data), 8):
        chunk = data[i:i+8]
        if len(chunk) < 8: break
        
        dec = bytes([b ^ 0xFF for b in chunk])
        
        try:
            t = struct.unpack('<I', dec[0:4])[0]
            id1 = dec[4]
            id2 = dec[5]
            id3 = dec[6]
            id4 = dec[7]
            
            print(f"Offset {i:4d} | T: {t:8d} (0x{t:08X}) | IDs: {id1:3d} {id2:3d} {id3:3d} {id4:3d}")
        except:
            pass

analyze(hex_str)
